-- ── Admin user (manual step) ───────────────────────────────────────────
-- The 'users' table FKs auth.users(id), so an admin account must first be
-- created through Supabase Auth. From the Supabase dashboard:
--   1. Authentication → Users → "Add user" → email + password.
--   2. Edit the new user's app_metadata to:
--        { "squadron_id": "00000000-0000-0000-0000-000000000001", "role": "admin" }
--      (RLS on every table reads squadron_id from this claim.)
--   3. Then run, replacing <auth-user-uuid> with the new user's id:
--
--      insert into users (id, squadron_id, username, display_name, role)
--      values ('<auth-user-uuid>', '00000000-0000-0000-0000-000000000001', 'ops.lead', 'Ops Lead', 'admin');
